const data = $input.first().json;
const name = data.visitor_name?.split(' ')[0] || 'there';
const phone = data.visitor_phone?.replace('+', '') || '';
const date = new Date(data.visit_date).toLocaleDateString('en-US', { weekday: 'long', day: 'numeric', month: 'long' });
const time = data.visit_time || '10:00';
const property = data.visit?.properties?.title || 'the property';

const message = `Hi ${name}! ✅ Your showing has been confirmed.

🏠 Property: ${property}
📅 Date: ${date}
⏰ Time: ${time}

Our agent will meet you at the property. Please bring a valid ID.

If you need to reschedule, reply to this message or call us.

See you soon! 🙂`;

return [{ json: { ...data, message, phone } }];
